import React, { useEffect, useState } from 'react';
import axios from 'axios';

function App() {
  const [sanPhams, setSanPhams] = useState([]);

  useEffect(() => {
    // Gọi API lấy dữ liệu
    axios.get('http://localhost:5000/api/san-pham')
      .then(res => setSanPhams(res.data))
      .catch(err => console.error("Lỗi API:", err));
  }, []);

  return (
    <div style={{ padding: '20px', backgroundColor: '#f5f5f5', minHeight: '100vh', fontFamily: 'Arial' }}>
      <h1 style={{ textAlign: 'center', marginBottom: '30px' }}>🖥️ HỆ THỐNG BUILD PC TỰ CHỌN</h1>
      
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', 
        gap: '20px' 
      }}>
        {sanPhams.map(item => (
          <div key={item._id} style={{ 
            backgroundColor: 'white', 
            borderRadius: '12px', 
            padding: '15px', 
            boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
            textAlign: 'center'
          }}>
            {/* Hiển thị hình ảnh từ field 'anh' trong database */}
            <div style={{ height: '180px', marginBottom: '15px' }}>
              <img 
                src={item.anh || 'https://via.placeholder.com/150'} 
                alt={item.ten} 
                style={{ maxHeight: '100%', maxWidth: '100%', objectFit: 'contain' }} 
              />
            </div>
            
            <h3 style={{ fontSize: '18px', color: '#333' }}>{item.ten}</h3>
            <p style={{ color: '#666' }}>Loại: <b>{item.loai}</b></p>
            <p style={{ color: '#e74c3c', fontSize: '20px', fontWeight: 'bold' }}>
              {item.gia?.toLocaleString()} VNĐ
            </p>
            
            <button style={{ 
              backgroundColor: '#007bff', 
              color: 'white', 
              border: 'none', 
              padding: '10px 20px', 
              borderRadius: '5px', 
              cursor: 'pointer',
              fontWeight: 'bold'
            }}>
              Thêm vào cấu hình
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
